import{_ as a,o,c as i,a2 as t}from"./chunks/framework.BuL2a98s.js";const b=JSON.parse('{"title":"Ruta del Curso","description":"","frontmatter":{},"headers":[],"relativePath":"guide/curso.md","filePath":"guide/curso.md"}'),r={name:"guide/curso.md"};function d(c,e,l,n,s,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="ruta-del-curso" tabindex="-1">Ruta del Curso <a class="header-anchor" href="#ruta-del-curso" aria-label="Permalink to &quot;Ruta del Curso&quot;">​</a></h1><p>Esta ruta organiza los ejemplos del repositorio como un curso corto de sistemas digitales con FPGA Gowin. La idea es que cada práctica se pueda ejecutar en placa y también leer como una unidad de teoría aplicada.</p><h2 id="objetivo-general" tabindex="-1">Objetivo General <a class="header-anchor" href="#objetivo-general" aria-label="Permalink to &quot;Objetivo General&quot;">​</a></h2><p>Al terminar el curso, el estudiante debe poder leer, modificar, sintetizar y cargar diseños digitales pequeños en Verilog y VHDL usando <code>DevLab</code>. El recorrido avanza desde <strong>compuertas</strong> y <strong>bloques combinacionales</strong> hasta <strong>contadores</strong> y <strong>máquinas de estado</strong>.</p><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><ul><li>Manejo básico de la terminal.</li><li>Conceptos de álgebra booleana: <strong>AND</strong>, <strong>OR</strong>, <strong>NOT</strong>, <strong>XOR</strong> y <strong>tablas de verdad</strong>.</li><li>Representación binaria de números enteros.</li><li>Instalación funcional de DevLab y toolchain Gowin.</li><li>Tarjeta FPGA conectada y archivo <code>pins.cst</code> correspondiente.</li><li>Esquemático de la tarjeta para validar pines, voltajes y conexiones.</li></ul><h2 id="flujo-de-trabajo-por-practica" tabindex="-1">Flujo de Trabajo por Práctica <a class="header-anchor" href="#flujo-de-trabajo-por-practica" aria-label="Permalink to &quot;Flujo de Trabajo por Práctica&quot;">​</a></h2><ol><li>Leer el objetivo y la teoría mínima.</li><li>Revisar <code>src/digital_labs.v</code> cuando exista un módulo reutilizable.</li><li>Revisar <code>src/top.v</code> para entender como se conecta el módulo a botones, reloj y LED.</li><li>Compilar con <code>devlab build</code>.</li><li>Cargar con <code>devlab flash</code>.</li><li>Repetir con VHDL usando <code>devlab build -c devlab-vhdl.toml</code>.</li><li>Registrar observaciones y contestar las preguntas de cierre.</li></ol><h2 id="evaluacion-recomendada" tabindex="-1">Evaluación Recomendada <a class="header-anchor" href="#evaluacion-recomendada" aria-label="Permalink to &quot;Evaluación Recomendada&quot;">​</a></h2><ul><li>Evidencia de compilación sin errores.</li><li>Evidencia de carga en placa.</li><li>Tabla de verdad o tabla de estados cuando aplique.</li><li>Explicación breve de entradas, salidas y señales internas.</li><li>Modificación pequeña propuesta en la sección de actividades.</li></ul><h2 id="secuencia-sugerida" tabindex="-1">Secuencia Sugerida <a class="header-anchor" href="#secuencia-sugerida" aria-label="Permalink to &quot;Secuencia Sugerida&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sesión</th><th>Prácticas</th><th>Tema central</th><th>Producto esperado</th></tr></thead><tbody><tr><td>1</td><td>Básicos, 01</td><td>Flujo DevLab, pines, LED activo en bajo, suma binaria</td><td>Primer bitstream cargado y tabla de suma de 1 bit</td></tr><tr><td>2</td><td>02, 03</td><td>Resta, préstamo y comparadores</td><td>Comparación entre operaciones aritméticas y relacionales</td></tr><tr><td>3</td><td>04, 05</td><td>Decodificadores y exhibidores</td><td>Tabla de segmentos para valores de entrada</td></tr><tr><td>4</td><td>06, 07</td><td>Composición de bloques y ALU</td><td>Bloque combinacional con selector de operación</td></tr><tr><td>5</td><td>08, 09, 10</td><td>Reloj, registros y contadores</td><td>Contadores visibles mediante divisor de frecuencia</td></tr><tr><td>6</td><td>11, 12</td><td>Control secuencial con dirección, enable y reset</td><td>Contador controlado desde botones</td></tr><tr><td>7</td><td>13, 14</td><td>Máquinas Moore y Mealy</td><td>Detector de secuencia <code>101</code> comparando ambos estilos</td></tr></tbody></table><h2 id="mapa-de-conceptos" tabindex="-1">Mapa de Conceptos <a class="header-anchor" href="#mapa-de-conceptos" aria-label="Permalink to &quot;Mapa de Conceptos&quot;">​</a></h2><ul><li>Combinacional: la salida depende solo de las entradas actuales.</li><li>Secuencial: la salida también depende del estado guardado en registros.</li><li><code>top</code>: módulo o entidad que conecta el diseño con pines físicos.</li><li><code>pins.cst</code>: restricciones que asignan puertos HDL a pines de la FPGA.</li><li>Esquemático: referencia eléctrica para confirmar que el pin usado en <code>pins.cst</code> corresponde al recurso físico correcto.</li><li>LED activo en bajo: <code>led_n = 0</code> enciende el LED y <code>led_n = 1</code> lo apaga.</li><li>Reset activo en bajo: <code>key_reset_n = 0</code> reinicia el circuito.</li><li>VHDL y Verilog describen el mismo hardware con sintaxis distinta.</li></ul><h2 id="proyecto-de-cierre" tabindex="-1">Proyecto de Cierre <a class="header-anchor" href="#proyecto-de-cierre" aria-label="Permalink to &quot;Proyecto de Cierre&quot;">​</a></h2><p>Extiende una práctica secuencial para mostrar más de una salida. Una opción viable es tomar el contador de la práctica 12 y cambiar el <code>top</code> para observar otro bit de <code>count</code>, agregar una dirección configurable o combinarlo con un decodificador de segmentos. El entregable debe incluir:</p><ul><li>Descripción del cambio.</li><li>Fragmento HDL modificado.</li><li>Resultado de <code>devlab build</code>.</li><li>Observación en placa.</li><li>Diferencia entre la versión Verilog y la versión VHDL si se implementaron ambas.</li></ul>',17)])])}const m=a(r,[["render",d]]);export{b as __pageData,m as default};
